  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return 1; // Return error if connection fails
  }
  auto conn = conn_result.value();

  // Begin transaction
  auto transaction_result = sqlgen::begin_transaction(conn);
  if (!transaction_result) {
    return 1; // Return error if transaction fails
  }
  auto transaction = transaction_result.value();

  // Create delete statement with condition
  auto delete_stmt = sqlgen::delete_from<User> 
                   | sqlgen::where("last_login"_c < "2025-01-01");

  // Execute the delete operation
  auto delete_result = delete_stmt(conn);
  if (!delete_result) {
    transaction.rollback();
    return 1; // Return error if delete fails
  }

  // Commit the transaction
  auto commit_result = transaction.commit();
  if (commit_result) {
