namespace query_product_sales_report {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* tablename = "ProductSalesReport";
  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Build the query
    auto query = sqlgen::select_from<Product, "p">()
        .fields("p.category"_c, sqlgen::sum("s.quantity"_c).as("total_qty"), sqlgen::sum("s.amount"_c).as("total_amt"))
        | sqlgen::join<Sale, "s">("p.product_id"_c == "s.product_id"_c)
        | sqlgen::group_by("p.category"_c)
        | sqlgen::having("total_amt"_c > 5000);

    // Execute the query and get the result
    auto result = query(conn);
    if (!result) {
        return {};
    }

    // Read the results into a vector of CategoryReport
    std::vector<CategoryReport> reports;
    auto it = result.value();

    while (true) {
        auto batch = it->next_batch(100);
        if (!batch) {
            break;
        }

        for (const auto& row : *batch) {
            CategoryReport report;
            report.category = row[0].value();
            report.total_qty = std::stoi(row[1].value());
            report.total_amt = std::stod(row[2].value());
            reports.push_back(report);
        }
    }

    return reports;
}

}  // namespace query_product_sales_report

