#pragma once

#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_manage_indexes {

  struct Product {
    sqlgen::PrimaryKey<int> product_id;
    std::string sku;
    std::string name;
    std::string category;
    double price;
  };

  bool manage_indexes() {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false;
    }
    auto conn = *conn_result;

    // Create the Product table
    auto create_table_stmt = sqlgen::create_table<Product>;
    std::string create_table_sql = create_table_stmt.to_sql();
    auto result = conn->execute(create_table_sql);
    if (!result) {
      return false;
    }

    // Create indexes with IF NOT EXISTS
    auto idx_category = sqlgen::create_index<"idx_product_category"> 
        | sqlgen::on<Product>("category"_c) 
        | sqlgen::if_not_exists;
    std::string sql_category = idx_category.to_sql();
    result = conn->execute(sql_category);
    if (!result) {
      return false;
    }

    auto idx_sku = sqlgen::create_unique_index<"idx_product_sku"> 
        | sqlgen::on<Product>("sku"_c) 
        | sqlgen::if_not_exists;
    std::string sql_sku = idx_sku.to_sql();
    result = conn->execute(sql_sku);
    if (!result) {
      return false;
    }

    auto idx_name_price = sqlgen::create_index<"idx_product_name_price"> 
        | sqlgen::on<Product>("name"_c, "price"_c) 
        | sqlgen::if_not_exists;
    std::string sql_name_price = idx_name_price.to_sql();
    result = conn->execute(sql_name_price);
    if (!result) {
      return false;
    }

    return true;
  }

}  // namespace schema_manage_indexes

