#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  auto update_sender = sqlgen::update<Account> 
                     | sqlgen::set(Account.balance = Account.balance - amount) 
                     | sqlgen::where(Account.account_id == from_account_id && Account.balance >= amount);

  auto update_receiver = sqlgen::update<Account> 
                     | sqlgen::set(Account.balance = Account.balance + amount) 
                     | sqlgen::where(Account.account_id == to_account_id);

  auto transaction = sqlgen::Transaction<decltype(conn)>(conn);

  auto result = transaction([&]() {
    // Execute sender update
    auto result_sender = update_sender(conn);
    if (!result_sender) {
      return sqlgen::error("Failed to update sender");
    }
    auto row_count = conn.changes();
    if (row_count != 1) {
      return sqlgen::error("Sender update affected " + std::to_string(row_count) + " rows, expected 1");
    }

    // Execute receiver update
    auto result_receiver = update_receiver(conn);
    if (!result_receiver) {
      return sqlgen::error("Failed to update receiver");
    }
    row_count = conn.changes();
    if (row_count != 1) {
      return sqlgen::error("Receiver update affected " + std::to_string(row_count) + " rows, expected 1");
    }

    return sqlgen::Nothing{};
  });

  return result;
}

}  // namespace transaction_transfer_funds

