```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace upsert_user_profile {

struct UserProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::optional<std::string> bio;
  std::optional<std::string> avatar_url;
};

bool upsert_user_profile(const UserProfile& u) {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // Create upsert statement using INSERT OR REPLACE
  auto stmt = sqlgen::insert<UserProfile> | sqlgen::or_replace;

  // Execute the statement
  auto result = stmt(conn, u);
  return result.is_ok();
}

} // namespace upsert_user_profile
```

## Explanation:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish a connection to the SQLite database.

2. **Upsert Logic**: 
   - Uses `sqlgen::insert<UserProfile>` to create an insert statement for the UserProfile table
   - Chains with `sqlgen::or_replace` using the `|` operator to enable the OR REPLACE functionality
